import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { TeamService } from '../../../../core/services/team.service';
import { AuthService } from '../../../../core/services/auth.service';
import { TeamUpdateService } from '../../../../core/services/team-update.service';
import { NgZone, ApplicationRef } from '@angular/core';

@Component({
  selector: 'app-create-team',
  templateUrl: './create-team.component.html',
  styleUrls: ['./create-team.component.scss']
})
export class CreateTeamComponent implements OnInit {
  teamForm: FormGroup;
  isLoading = false;
  isSubmitting = false;
  errorMessage = '';
  successMessage = '';

  constructor(
    private fb: FormBuilder,
    private teamService: TeamService,
    private authService: AuthService,
    private router: Router,
    private teamUpdateService: TeamUpdateService,
    private ngZone: NgZone,
    private appRef: ApplicationRef
  ) {
    this.teamForm = this.fb.group({
      nomeTeam: ['', [Validators.required, Validators.minLength(3), Validators.maxLength(50)]]
    });
  }

  ngOnInit(): void {
    console.log('CreateTeamComponent - Initializing...');
  }

  createTeam(): void {
    console.log('CreateTeamComponent - createTeam called');
    console.log('CreateTeamComponent - Form valid:', this.teamForm.valid);
    console.log('CreateTeamComponent - Form value:', this.teamForm.value);
    console.log('CreateTeamComponent - Token in localStorage:', localStorage.getItem('token'));

    if (this.teamForm.invalid) {
      // Mark all fields as touched to trigger validation messages
      Object.keys(this.teamForm.controls).forEach(key => {
        this.teamForm.get(key)?.markAsTouched();
      });
      return;
    }

    this.isSubmitting = true;
    this.errorMessage = '';
    this.successMessage = '';

    const teamData = {
      nomeTeam: this.teamForm.value.nomeTeam
    };

    console.log('CreateTeamComponent - Creating team with data:', teamData);

    this.teamService.creaTeam(teamData).subscribe({
      next: (response: any) => {
        console.log('CreateTeamComponent - Team created successfully:', response);

        // Aggiorna manualmente i dati utente nell'AuthService per aggiornare la headbar
        const currentUser = this.authService.currentUser;
        if (currentUser) {
          currentUser.ruolo = 'LEADER_TEAM';
          // Forza aggiornamento del BehaviorSubject
          this.authService.updateCurrentUserLocally(currentUser);
        }

        // Navigate to teams page
        this.router.navigate(['/teams']).then(() => {
          // Forza ricarica dei dati dei team dopo un breve delay
          setTimeout(() => {
            // Forza change detection su tutta l'applicazione
            this.ngZone.run(() => {
              this.appRef.tick();
            });
          }, 200);
        });
      },
      error: (error: any) => {
        console.error('CreateTeamComponent - Error creating team:', error);
        console.error('CreateTeamComponent - Error status:', error.status);
        console.error('CreateTeamComponent - Error message:', error.message);
        console.error('CreateTeamComponent - Error details:', error.error);

        if (error.status === 403) {
          this.errorMessage = 'Only users without a team can create a new team.';
        } else if (error.status === 409) {
          this.errorMessage = 'A team with this name already exists. Please choose a different name.';
        } else {
          this.errorMessage = error.error?.message || 'Failed to create team. Please try again.';
        }
        this.isSubmitting = false;
      }
    });
  }

  goBack(): void {
    console.log('CreateTeamComponent - Going back to teams');
    this.router.navigate(['/teams']);
  }

  clearError(): void {
    this.errorMessage = '';
  }

  // Helper method for form validation
  get nomeTeam() { return this.teamForm.get('nomeTeam'); }
}
<div class="create-team-container">
  <!-- Page Header -->
  <div class="page-header">
    <button class="back-button" (click)="goBack()">
      <span>←</span>
      <span>Back</span>
    </button>
    <h1 class="page-title">Create New Team</h1>
    <p class="page-subtitle">Create your team and start collaborating on hackathons</p>
  </div>

  <!-- Loading State -->
  <div class="loading-state" *ngIf="isLoading">
    <div class="loading-spinner">
      <div class="spinner"></div>
      <p>Creating team...</p>
    </div>
  </div>

  <!-- Error State -->
  <div class="error-state" *ngIf="errorMessage">
    <div class="error-card">
      <div class="error-icon">⚠️</div>
      <h3>Oops! Something went wrong</h3>
      <p>{{ errorMessage }}</p>
      <button class="btn-secondary" (click)="clearError()">Try Again</button>
    </div>
  </div>

  <!-- Create Team Form -->
  <div class="create-team-form" *ngIf="!isLoading && !errorMessage">
    <form (ngSubmit)="createTeam()" [formGroup]="teamForm">
      <div class="form-section">
        <h2>Team Information</h2>

        <!-- Team Name -->
        <div class="form-group">
          <label for="nomeTeam">Team Name *</label>
          <input 
            type="text" 
            id="nomeTeam" 
            formControlName="nomeTeam"
            placeholder="Enter your team name"
            [class.error]="teamForm.get('nomeTeam')?.invalid && teamForm.get('nomeTeam')?.touched"
            autocomplete="off"
          >
          <div class="error-message" *ngIf="teamForm.get('nomeTeam')?.invalid && teamForm.get('nomeTeam')?.touched">
            <span *ngIf="teamForm.get('nomeTeam')?.errors?.['required']">Team name is required</span>
            <span *ngIf="teamForm.get('nomeTeam')?.errors?.['minlength']">Team name must be at least 3 characters</span>
            <span *ngIf="teamForm.get('nomeTeam')?.errors?.['maxlength']">Team name cannot exceed 50 characters</span>
          </div>
          <div class="help-text">
            Team name must be unique and contain 3-50 characters
          </div>
        </div>
      </div>

      <!-- Important Information -->
      <div class="info-section">
        <div class="info-card">
          <div class="info-icon">ℹ️</div>
          <div class="info-content">
            <h3>Important Information</h3>
            <ul>
              <li>You will automatically become the team leader</li>
              <li>Team name must be unique across all teams</li>
              <li>You can invite members after creating the team</li>
              <li>Only users without a team can create a new team</li>
            </ul>
          </div>
        </div>
      </div>

      <!-- Form Actions -->
      <div class="form-actions">
        <button type="button" class="btn-secondary" (click)="goBack()">
          Cancel
        </button>
        <button type="submit" class="btn-primary" [disabled]="teamForm.invalid || isSubmitting">
          <span *ngIf="!isSubmitting">Create Team</span>
          <span *ngIf="isSubmitting">Creating...</span>
        </button>
      </div>
    </form>
  </div>
</div>
